        required this.allowTrailingCommas,
        required this.allOf,
        required this.definitions,
        required this.id,
        required this.title,
        required this.type,
    });

    factory TsconfigSchemastoreSchema.fromJson(Map<String, dynamic> json) => TsconfigSchemastoreSchema(
        schema: json["\u0024schema"],
        allowTrailingCommas: json["allowTrailingCommas"],
        allOf: List<AllOf>.from(json["allOf"].map((x) => AllOf.fromJson(x))),
        definitions: Definitions.fromJson(json["definitions"]),
        id: json["id"],
        title: json["title"],
        type: typeValues.map[json["type"]]!,
