    Map<String, dynamic> toJson() => {
        "\u0024schema": schema,
        "allowTrailingCommas": allowTrailingCommas,
        "allOf": List<dynamic>.from(allOf.map((x) => x.toJson())),
        "definitions": definitions.toJson(),
        "id": id,
        "title": title,
        "type": typeValues.reverse[type],
    };
}

